/// imageId : 138
/// imageData : "data:image/jpg;base64,"
/// message : "SUCCESS"

class ImageListModel {
  ImageListModel({
      num? imageId, 
      String? imageData, 
      String? message,}){
    _imageId = imageId;
    _imageData = imageData;
    _message = message;
}

  ImageListModel.fromJson(dynamic json) {
    _imageId = json['imageId'];
    _imageData = json['imageData'];
    _message = json['message'];
  }
  num? _imageId;
  String? _imageData;
  String? _message;

  num? get imageId => _imageId;
  String? get imageData => _imageData;
  String? get message => _message;

  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['imageId'] = _imageId;
    map['imageData'] = _imageData;
    map['message'] = _message;
    return map;
  }

}